static void esc(FILE *fp, const char *s) {
    fputc('"', fp);
    for (const char *p = s; *p; p++) {
        if (*p == '"' || *p == '\\') {
            fputc('\\', fp);
        }
        fputc(*p, fp);
    }
    fputc('"', fp);
}

static void write_case(FILE *fp, const SolveResult *res, int last) {
    fprintf(fp, "    {\n      \"name\": ");
