static int run_named(const char *name, const char *out_dir, SolveResult *res) {
    char path[512];
    CaseSpec spec;
    snprintf(path, sizeof(path), "/app/data/cases/%s.case", name);
    if (case_load(path, &spec) != 0) {
        return -1;
